function solve(n, edges, k) {
    // Sort edges by their removal time
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find data structure
    const uf = new UnionFind(n);

    let result = 0;
    let components = n; // Initially, each node is its own component

    for (const [u, v, time] of edges) {
        // Check if the nodes are in the same component
        if (uf.find(u) !== uf.find(v)) {
            // If they are in different components, merging them will decrease the number of components
            uf.union(u, v);
            components--;
        }

        // If we have reached the required number of components, return the current time
        if (components === k) {
            return time;
        }
    }

    // If we haven't found the required components, return the maximum time
    return edges[edges.length - 1][2];
}

// Union-Find data structure implementation
class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) return false;

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
        return true;
    }
